descriptor.templateCss:
:host { 
    height: 100%; 
    width: 100%; 
    display: flex !important; /* Force flex on the host */
    flex-direction: column;
}

.ota-card { 
    background: #ffffff; 
    color: #1f2937; 
    padding: 24px; 
    border-radius: 20px; 
    font-family: 'Inter', -apple-system, system-ui, sans-serif;
    box-shadow: 0 10px 30px rgba(0,0,0,0.08);
    
    /* This ensures it fills the height but respects padding */
    flex: 1; 
    margin: 10px;
    
    display: flex;
    flex-direction: column;
    min-width: 320px; /* Prevents the "tiny cube" look */
    border: 1px solid #f3f4f6;
}

.ota-header { 
    display: flex; 
    justify-content: space-between; 
    align-items: center; 
    margin-bottom: 24px; 
    border-bottom: 2px solid #f3f4f6; 
    padding-bottom: 16px; 
}

.room-title { font-weight: 800; font-size: 1.3em; color: #2563eb; letter-spacing: -0.02em; }

#status-tag { padding: 6px 12px; border-radius: 99px; font-size: 0.7em; font-weight: 800; }
.status-pending { background: #fef3c7; color: #92400e; }
.status-synced { background: #dcfce7; color: #166534; }

.current-stats { 
    display: flex; 
    gap: 30px; 
    margin-bottom: 24px; 
    background: #f9fafb; 
    padding: 18px; 
    border-radius: 16px; 
    border: 1px solid #f3f4f6;
}

.ota-inputs { display: grid; gap: 20px; margin-bottom: 24px; }
.input-row input { 
    width: 100%; 
    box-sizing: border-box; /* Crucial for width: 100% */
    background: #fff; 
    border: 2px solid #e5e7eb; 
    padding: 12px; 
    border-radius: 12px; 
    font-weight: 500;
}

#updateBtn { 
    margin-top: auto; /* Pushes button to bottom */
    width: 100%; 
    background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%); 
    color: #fff; 
    border: none; 
    padding: 16px; 
    border-radius: 14px; 
    font-weight: 700; 
    cursor: pointer; 
    transition: all 0.2s ease;
}

descriptor.controllerScript:
self.onInit = function() {
    const container = self.ctx.$container;
    const ctx = self.ctx;

    // 1. Resolve Target (State Entity > Dashboard Datasource)
    function getTarget() {
        let name = "Unknown Room";
        let id = null;

        // In 4.x, if your widget has a datasource, TB automatically 
        // binds the state entity to the first datasource.
        if (ctx.defaultSubscription && ctx.defaultSubscription.entityId) {
            name = ctx.defaultSubscription.entityName;
            id = ctx.defaultSubscription.entityId;
        } 
        else if (ctx.datasources && ctx.datasources[0] && ctx.datasources[0].entityId) {
            name = ctx.datasources[0].entityName;
            id = ctx.datasources[0].entityId;
        }
        
        // Final fallback: check for any entity in the state controller params
        if (!id && ctx.stateController && ctx.stateController.getStateParams) {
            const params = ctx.stateController.getStateParams();
            if (params && params.entityId) {
                id = params.entityId;
                name = params.entityName || "Room " + id.id.substring(0,5);
            }
        }

        return { name, id };
    }


    const target = getTarget();
    container.find('#targetId').text(target.name);

    // 2. Real-time Telemetry Processing
    self.onDataUpdated = function() {
        const data = ctx.data;
        if (!data || data.length === 0) return;

        const findVal = (key) => {
            const d = data.find(item => item.dataKey.name === key || item.dataKey.label === key);
            return (d && d.data && d.data.length) ? d.data[0][1] : undefined;
        };
        
        const alpha = findVal('alpha');
        const version = findVal('current_version');
        
        if (alpha !== undefined) container.find('#currAlpha').text(parseFloat(alpha).toFixed(2));
        if (version !== undefined) container.find('#currVersion').text(version);
        
        // Dynamic Sync Status
        const targetVer = container.find('#newVersion').val();
        const statusTag = container.find('#status-tag');
        if (version && version.toString() === targetVer.toString()) {
            statusTag.text('SYNCED').removeClass('status-pending').addClass('status-synced');
        } else {
            statusTag.text('PENDING SYNC').addClass('status-pending').removeClass('status-synced');
        }
    };

    // 3. Deploy Button Action
    container.find('#updateBtn').on('click', async function() {
        const nAlpha = parseFloat(container.find('#newAlpha').val());
        const nBeta = parseFloat(container.find('#newBeta').val());
        const nVersion = container.find('#newVersion').val();
        
        if (isNaN(nAlpha) || isNaN(nBeta)) return ctx.showErrorToast("Enter valid numbers");
        if (!target.id) return ctx.showErrorToast("No target device");

        // Physics Parameter Hash (SHA-256)
        const config = JSON.stringify({alpha: nAlpha, beta: nBeta});
        const msgBuffer = new TextEncoder().encode(config);
        const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
        const signature = Array.from(new Uint8Array(hashBuffer))
                            .map(b => b.toString(16).padStart(2, '0')).join('');

        ctx.attributeService.saveEntityAttributes(target.id, "SHARED_SCOPE", {
            config_data: config,
            signature: signature,
            target_version: nVersion,
            target: target.name
        }).subscribe(
            () => ctx.showSuccessToast("Evolution deployed to " + target.name),
            (err) => ctx.showErrorToast("Deploy failed: " + err)
        );
    });
};
